document.addEventListener("DOMContentLoaded", () => {
    const widthScreen = window.innerWidth || document.documentElement.clientWidth ||
        document.body.clientWidth;

    Fancybox.bind("[data-fancybox]", {
        placeFocusBack: false
    });

    if (document.getElementById('homeSlider')) {
        const progressPage = document.getElementById("homeSlider");
        new Swiper('#homeSlider', {
            lazyPreloadPrevNext: 1,
            spaceBetween: 26,
            slidesPerView: 1,
            loop: true,
            autoplay: {
                delay: 2000,
                disableOnInteraction: false,
            },
            parallax: true,
            speed: 1000,
            pagination: {
                el: '.home-slider__paginate',
                clickable: true,
            },
            on: {
                autoplayTimeLeft(s, time, progress) {
                    progressPage.style.setProperty("--progress", ((1 - progress) * 100) + '%');
                }
            }
        });
    }
    if (document.getElementById('gallerySlider')) {

        new Swiper('#gallerySlider', {
            lazyPreloadPrevNext: 2,
            spaceBetween: 16,
            slidesPerView: 3,
            navigation: {
                nextEl: '#gallerySliderNext',
                prevEl: '#gallerySliderPrev',
            },
        });
    }

    if (document.getElementById('partnersSlider')) {
        if (document.getElementById('partnersSlider')) {
            new Swiper('#partnersSlider', {
                lazyPreloadPrevNext: 1,
                spaceBetween: 50,
                slidesPerView: 'auto',
                //loop: true,

            });
        }
    }

    //window.scrollTo(0, 0);
    gsap.registerPlugin(ScrollTrigger);


    let fade_in = gsap.utils.toArray('.home-prim__item.fade_in');
    fade_in.forEach((item, idx) => {
        gsap.fromTo(item, {opacity: 0, y: 20}, {
            opacity: 1,
            duration: 0.8,
            y: 0,
            delay: idx * 0.2,
            ease: "power2.out",
            scrollTrigger: {
                trigger: item,
                start: "top 60%",
                end: "top 90%",
                ease: "power3.InOut",
                //markers: true,
            },
            clearProps: "all",
            onStart: () => {
                item.classList.add('animating');
            }
        })
    });

    let fade_in2 = gsap.utils.toArray('.home-about__adv.fade_in');
    fade_in2.forEach((item, idx) => {
        gsap.fromTo(item, {opacity: 0, y: 20}, {
            opacity: 1,
            duration: 0.8,
            y: 0,
            delay: idx * 0.2,
            ease: "power2.out",
            scrollTrigger: {
                trigger: item,
                start: "top 60%",
                end: "top 90%",
                ease: "power3.InOut",
                // markers: true,
            },
            clearProps: "all",
            onStart: () => {
                item.classList.add('animating');
            }
        })
    });
    if(widthScreen > 991) {
        let fade_in3 = gsap.utils.toArray('.home-partners__item');
        fade_in3.forEach((item, idx) => {
            gsap.fromTo(item, {opacity: 0, y: 20}, {
                opacity: 1,
                duration: 0.8,
                y: 0,
                delay: idx * 0.2,
                ease: "power2.out",
                scrollTrigger: {
                    trigger: item,
                    start: "top 60%",
                    end: "top 90%",
                    ease: "power3.InOut",
                    // markers: true,
                },
                clearProps: "all",
                onStart: () => {
                    item.classList.add('animating');
                }
            })
        });
    }

    let fade_in_up = gsap.utils.toArray('.fade_in_up');
    fade_in_up.forEach((item, idx) => {
        gsap.fromTo(item, {opacity: 0, y: 20}, {
            opacity: 1,
            duration: 1,
            y: 0,
            delay: item.dataset.delay ? item.dataset.delay : 0,
            scrollTrigger: {
                trigger: item,
                start: "top 60%",
                end: "top 90%",
                ease: "power3.InOut",
            },
            clearProps: "all",
            onStart: () => {
                item.classList.add('animating');
            }
        })
    });


    if (document.getElementById('singleNav') && widthScreen > 991) {
        const nav = document.getElementById('singleNav');

        const observerOptions = {
            root: null,
            threshold: 0,
            rootMargin: "0px 0px 0px 0px"
        };

        const observer = new IntersectionObserver((entries) => {
            entries.forEach(entry => {

                if (!entry.isIntersecting) {
                    nav.classList.add('is-fixed');
                    document.body.classList.add('has-fixed-nav');
                } else {

                    nav.classList.remove('is-fixed');
                    document.body.classList.remove('has-fixed-nav');
                }
            });
        }, observerOptions);

        observer.observe(nav);
    }
});
